import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';
import { useAuth } from '../contexts/AuthContext';

const Dashboard = () => {
  const { user } = useAuth();
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchAnalytics();
  }, []);

  const fetchAnalytics = async () => {
    try {
      const response = await api.get('/analytics/dashboard/');
      setAnalytics(response.data);
    } catch (error) {
      console.error('Failed to fetch analytics:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div className="container" style={{ marginTop: '30px' }}>
      <h1>Maritime Platform Dashboard</h1>
      <p>Welcome back, {user?.first_name || user?.username}!</p>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px', marginTop: '30px' }}>
        
        {/* Quick Stats */}
        <div className="card">
          <h3>Quick Statistics</h3>
          {analytics ? (
            <div>
              <p><strong>Total Voyages:</strong> {analytics.summary.total_voyages}</p>
              <p><strong>Active Voyages:</strong> {analytics.summary.active_voyages}</p>
              <p><strong>Completed Voyages:</strong> {analytics.summary.completed_voyages}</p>
            </div>
          ) : (
            <p>No data available</p>
          )}
        </div>

        {/* Navigation Cards */}
        <div className="card">
          <h3>Vessel Tracking</h3>
          <p>Monitor real-time vessel positions and movements</p>
          <Link to="/vessels" className="btn btn-primary">
            View Vessels
          </Link>
        </div>

        <div className="card">
          <h3>Port Analytics</h3>
          <p>Analyze port congestion and traffic data</p>
          <Link to="/ports" className="btn btn-primary">
            View Ports
          </Link>
        </div>

        <div className="card">
          <h3>Safety Overlays</h3>
          <p>View safety zones and weather conditions</p>
          <Link to="/safety" className="btn btn-primary">
            View Safety Data
          </Link>
        </div>

        <div className="card">
          <h3>Analytics & Reports</h3>
          <p>Historical data and voyage analytics</p>
          <Link to="/analytics" className="btn btn-primary">
            View Analytics
          </Link>
        </div>

        {/* User Info */}
        <div className="card">
          <h3>Your Profile</h3>
          <p><strong>Role:</strong> {user?.role}</p>
          <p><strong>Company:</strong> {user?.company || 'Not specified'}</p>
          <p><strong>Email:</strong> {user?.email}</p>
        </div>
      </div>

      {/* Recent Events */}
      {analytics?.recent_events && analytics.recent_events.length > 0 && (
        <div className="card" style={{ marginTop: '30px' }}>
          <h3>Recent Events</h3>
          <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
            {analytics.recent_events.map((event, index) => (
              <div key={index} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>
                <strong>{event.event_type}</strong> - {event.description}
                <br />
                <small>{new Date(event.timestamp).toLocaleString()}</small>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
